import React, { useState } from "react";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: { display: false, drawBorder: false },
  ticks: { font: { size: 11 } },
};

function Dashboard() {
  const adminProfile = {
    name: "Admin",
    lastUpdated: new Date(),
  };

  const summaryCards = {
    totalUsers: 1250,
    totalLeads: 842,
    totalRevenue: 2450000,
    totalSupportTickets: 128,
  };

  /* ================= DUMMY DATA ================= */

  const dummyData = {
    2025: {
      1: {
        clients: 30,
        payments: 300000,
        leads: 100,
        approved: 80,
        duplicate: 20,
      },
      2: {
        clients: 40,
        payments: 450000,
        leads: 120,
        approved: 90,
        duplicate: 30,
      },
      3: {
        clients: 35,
        payments: 380000,
        leads: 110,
        approved: 85,
        duplicate: 25,
      },
    },
    2026: {
      1: {
        clients: 50,
        payments: 500000,
        leads: 140,
        approved: 110,
        duplicate: 30,
      },
      2: {
        clients: 60,
        payments: 620000,
        leads: 160,
        approved: 130,
        duplicate: 30,
      },
      3: {
        clients: 55,
        payments: 580000,
        leads: 150,
        approved: 130,
        duplicate: 20,
      },
      4: {
        clients: 70,
        payments: 720000,
        leads: 180,
        approved: 145,
        duplicate: 25,
      },
      5: {
        clients: 65,
        payments: 690000,
        leads: 170,
        approved: 140,
        duplicate: 30,
      },
      6: {
        clients: 80,
        payments: 810000,
        leads: 200,
        approved: 160,
        duplicate: 40,
      },
    },
  };

  /* ================= PAYMENTS FILTER ================= */

  const currentYear = new Date().getFullYear();
  const [paymentsYear, setPaymentsYear] = useState(currentYear);
  const [selectedMonth, setSelectedMonth] = useState("all");

  const paymentsYearData = dummyData[paymentsYear] || {};
  const paymentMonths = Object.keys(paymentsYearData);

  const filteredPaymentMonths =
    selectedMonth === "all"
      ? paymentMonths
      : paymentMonths.filter((m) => m === selectedMonth);

  const paymentLabels = filteredPaymentMonths.map((m) =>
    selectedMonth === "all"
      ? dayjs(`${paymentsYear}-${m}-01`).format("MMM YYYY")
      : dayjs(`${paymentsYear}-${m}-01`).format("MMM"),
  );

  const clientData = filteredPaymentMonths.map(
    (m) => paymentsYearData[m].clients,
  );
  const paymentData = filteredPaymentMonths.map(
    (m) => paymentsYearData[m].payments,
  );
  const commissionData = paymentData.map((amt) =>
    Number(((amt * 10) / 100).toFixed(0)),
  );

  const mergedChartData = {
    labels: paymentLabels,
    datasets: [
      {
        label: "Clients Converted",
        data: clientData,
        backgroundColor: "#0d6efd65",
        yAxisID: "yClients",
        borderRadius: 8,
      },
      {
        label: "Payments (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        yAxisID: "yAmount",
        borderRadius: 8,
      },
    ],
  };

  const mergedChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { ...commonGrid },
      yClients: {
        type: "linear",
        position: "left",
        beginAtZero: true,
        ...commonGrid,
      },
      yAmount: {
        type: "linear",
        position: "right",
        beginAtZero: true,
        grid: { drawOnChartArea: false },
        ticks: {
          callback: (v) =>
            v < 100000
              ? `₹${(v / 1000).toFixed(0)}k`
              : `₹${(v / 100000).toFixed(0)}L`,
        },
      },
    },
  };

  /* ================= LEAD CHART FILTER ================= */

  const [leadYear, setLeadYear] = useState(currentYear);

  const goToPreviousLeadYear = () => setLeadYear((prev) => prev - 1);
  const goToNextLeadYear = () => setLeadYear((prev) => prev + 1);

  const leadYearData = dummyData[leadYear] || {};
  const leadMonths = Object.keys(leadYearData);

  const leadLabels = leadMonths.map((m) =>
    dayjs(`${leadYear}-${m}-01`).format("MMM"),
  );

  const leadStatusData = {
    labels: leadLabels,
    datasets: [
      {
        label: "Total Leads",
        data: leadMonths.map((m) => leadYearData[m].leads),
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
      },
      {
        label: "Approved Leads",
        data: leadMonths.map((m) => leadYearData[m].approved),
        backgroundColor: "#19875475",
        borderRadius: 8,
      },
      {
        label: "Duplicate Leads",
        data: leadMonths.map((m) => leadYearData[m].duplicate),
        backgroundColor: "#dc354575",
        borderRadius: 8,
      },
    ],
  };

  const leadStatusOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { position: "top" } },
    scales: {
      x: { ...commonGrid },
      y: { beginAtZero: true, ...commonGrid },
    },
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <div className="row g-2">
        <div className="col-md-12 col-12">
          <h4 className="fw-bold fs-3">Welcome, {adminProfile.name}</h4>
        </div>
        <div className="col-md-12 col-12">
          <small>
            Last Updated:{" "}
            {dayjs(adminProfile.lastUpdated).format("DD MMM YYYY, hh:mm A")}
          </small>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="row g-3 pt-1">
        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-primary border-opacity-50">
            <small><i className="fas fa-users"></i>{" "}Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-success border-opacity-50">
            <small><i className="fas fa-user-plus"></i>{" "}Total Leads</small>
            <h5>{summaryCards.totalLeads}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-warning border-opacity-50">
            <small><i className="fas fa-indian-rupee-sign"></i>{" "}Total Revenue</small>
            <h5>₹{summaryCards.totalRevenue.toLocaleString("en-IN")}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 rounded bg-body border-start border-5 border-danger border-opacity-50">
            <small><i className="fas fa-headset"></i>{" "}Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      <div className="row pt-4 g-4">
        {/* Lead Chart */}
        <div className="col-lg-4 col-12">
          <div className="border rounded p-3 bg-body h-100 d-flex flex-column">
            <div className="d-flex justify-content-between align-items-center mb-2">
              <h6 className="fw-bold mb-0">
                <i className="fas fa-chart-column"></i>{" "}Leads ({leadYear})
              </h6>
              <div>
                <button
                  className="btn btn-outline-secondary border-0 btn-sm"
                  onClick={goToPreviousLeadYear}
                >
                  <i className="fa fa-chevron-left"></i>
                </button>
                <button
                  className="btn btn-outline-secondary border-0 btn-sm ms-1"
                  onClick={goToNextLeadYear}
                >
                  <i className="fa fa-chevron-right"></i>
                </button>
              </div>
            </div>

            <div style={{ flex: 1, minHeight: "300px" }}>
              <Bar data={leadStatusData} options={leadStatusOptions} />
            </div>
          </div>
        </div>

        {/* Payments Chart */}
        <div className="col-lg-8 col-12">
          <div className="border rounded p-3 bg-body h-100 d-flex flex-column">
            <div className="row g-2 align-items-center mb-2">
              <div className="col-lg-6 col-12">
                <h6 className="fw-bold mb-0">
                  Payments Overview ({paymentsYear})
                </h6>
              </div>

              <div className="col-lg-6 col-12">
                <div className="row g-2">
                  <div className="col-6">
                    <select
                      className="form-select form-select-sm"
                      value={paymentsYear}
                      onChange={(e) => setPaymentsYear(Number(e.target.value))}
                    >
                      {Object.keys(dummyData).map((year) => (
                        <option key={year} value={year}>
                          {year}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="col-6">
                    <select
                      className="form-select form-select-sm"
                      value={selectedMonth}
                      onChange={(e) => setSelectedMonth(e.target.value)}
                    >
                      <option value="all">All Months</option>
                      {paymentMonths.map((month) => (
                        <option key={month} value={month}>
                          {dayjs(`${paymentsYear}-${month}-01`).format("MMM")}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
            </div>

            <div style={{ flex: 1, minHeight: "300px" }}>
              {paymentLabels.length ? (
                <Bar data={mergedChartData} options={mergedChartOptions} />
              ) : (
                <div className="d-flex justify-content-center align-items-center h-100 text-muted">
                  No data available
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
